export interface PageGuide {
  slug: string;
  titre: string;
  h1: string;
  metaDescription: string;
  contenu: string;
}

export function getGuideBySlug(slug: string): PageGuide | undefined {
  return pagesGuides.find((p) => p.slug === slug);
}

